policies.inbound:



    {{EntraAudience}}


    https://login.microsoftonline.com/{{EntraTenantId}}/v2.0
    https://sts.windows.net/{{EntraTenantId}}/







  @{
    var jwt = context.Request.Headers.GetValueOrDefault("Authorization","").Split(' ').Last();
    var claims = context.Request.Headers.GetValueOrDefault("Authorization","");
    return context.Request.Headers.GetValueOrDefault("Authorization","")
      .Split(' ').Last()
      .Split('.')[1]
      .PadRight(4 * ((context.Request.Headers.GetValueOrDefault("Authorization","").Split(' ').Last().Split('.')[1].Length + 3) / 4), '=');
  }



    {{StaffPortalOrigin}}
    {{CustomerPortalOrigin}}


    GET
    POST
    PUT
    PATCH
    DELETE
    OPTIONS


    *


    X-Request-Id
    X-Correlation-Id




  @(Guid.NewGuid().ToString())

<rate-limit-by-key calls="1000" renewal-period="60"
                   counter-key="@(context.Request.Headers.GetValueOrDefault("X-Tenant-Id","anonymous"))"
                   increment-condition="@(context.Response.StatusCode >= 200 && context.Response.StatusCode < 400)" />
